shellspec_matcher_be_empty_file() {
  shellspec_matcher__match() {
    shellspec_is_empty_file "${SHELLSPEC_SUBJECT:-}"
  }

  shellspec_syntax_failure_message + \
    'The specified path is not empty file' \
    'path: $SHELLSPEC_SUBJECT'
  shellspec_syntax_failure_message - \
    'The specified path is empty file' \
    'path: $SHELLSPEC_SUBJECT'

  shellspec_syntax_param count [ $# -eq 0 ] || return 0
  shellspec_matcher_do_match
}

shellspec_matcher_be_empty_directory() {
  shellspec_matcher__match() {
    shellspec_is_empty_directory "${SHELLSPEC_SUBJECT:-}"
  }

  shellspec_syntax_failure_message + \
    'The specified path is not empty directory' \
    'path: $SHELLSPEC_SUBJECT'
  shellspec_syntax_failure_message - \
    'The specified path is empty directory' \
    'path: $SHELLSPEC_SUBJECT'

  shellspec_syntax_param count [ $# -eq 0 ] || return 0
  shellspec_matcher_do_match
}

function release-finish {
	about 'helper function for finishing a release'
	group 'jgitflow'

	pre-jgitflow && mvn jgitflow:release-finish -Darguments="${JGITFLOW_MVN_ARGUMENTS}" && git push && git push origin master && git push --tags && mvn clean
}

function cless() {
	about 'pigments the files passed in and passes to less for pagination'
	param '*: the files to paginate with less'
	example 'cless mysite/manage.py'

	pygmentize -f 256 -O style="${BASH_IT_CLESS_STYLE:-default}" -g "$@" | command less -R
}
